namespace sv_239478b62d274f3db589cc2c39d2c712.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new(NextId(), "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new(NextId(), "Your profile has been set up.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new(NextId(), "You have 3 pending tasks.", DateTime.UtcNow.AddMinutes(-2)));
    }

    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>
    /// Returns notifications added after the given ID (for polling).
    /// Also randomly generates a new notification ~30% of the time to simulate activity.
    /// </summary>
    public List<Notification> GetNotificationsSince(int lastSeenId)
    {
        lock (_lock)
        {
            MaybeGenerateNew();
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    private void MaybeGenerateNew()
    {
        if (Random.Shared.NextDouble() < 0.3)
        {
            string[] messages =
            [
                "New comment on your post.",
                "Deployment completed successfully.",
                "A teammate mentioned you.",
                "Build #42 failed — check logs.",
                "Your subscription renews tomorrow.",
                "Security alert: new login detected.",
            ];

            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new(NextId(), msg, DateTime.UtcNow));
        }
    }

    private int NextId() => _nextId++;
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification>? notifications;
    private CancellationTokenSource? cts;
    private int lastSeenId;

    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    protected override void OnInitialized()
    {
        // Restore from persisted prerender state, or load fresh
        PersistedNotifications ??= NotificationService.GetNotifications();
        notifications = PersistedNotifications;
        lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(5000, cancellationToken);

            var newItems = NotificationService.GetNotificationsSince(lastSeenId);
            if (newItems.Count > 0)
            {
                notifications!.AddRange(newItems);
                lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        cts?.Cancel();
        cts?.Dispose();
    }
}

