namespace sv_239478b62d274f3db589cc2c39d2c712.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();

    public NotificationService()
    {
        _notifications.Add(new(NextId(), "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new(NextId(), "Your profile has been set up.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new(NextId(), "You have 3 pending tasks.", DateTime.UtcNow.AddMinutes(-2)));
    }

    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>
    /// Returns notifications added after the given ID.
    /// Randomly generates a new notification ~30% of the time to simulate activity.
    /// </summary>
    public List<Notification> GetNotificationsSince(int lastSeenId)
    {
        lock (_lock)
        {
            MaybeGenerateNew();
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    private void MaybeGenerateNew()
    {
        if (Random.Shared.NextDouble() < 0.3)
        {
            string[] messages =
            [
                "New comment on your post.",
                "Deployment completed successfully.",
                "A teammate mentioned you.",
                "Build #42 failed — check logs.",
                "Your subscription renews tomorrow.",
                "Security alert: new login detected.",
            ];

            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new(NextId(), msg, DateTime.UtcNow));
        }
    }

    private int NextId() => _nextId++;
}

